$ok = 0; $skip = 0; $err = [];
foreach ($posts as $p) {
    [$cat_id,$title,$slug,$content,$excerpt,$author,$image,$status,$views,$is_featured,$is_breaking,$is_top,$is_curated] = $p;
    $t  = $conn->real_escape_string($title);
    $sl = $conn->real_escape_string($slug);
    $c  = $conn->real_escape_string($content);
    $ex = $conn->real_escape_string($excerpt);
    $au = $conn->real_escape_string($author);
    $im = $conn->real_escape_string($image);
    $st = $conn->real_escape_string($status);
    $sql = "INSERT IGNORE INTO posts (title,slug,content,excerpt,category_id,author,image,status,views,is_featured,is_breaking,is_top,is_curated)
            VALUES ('$t','$sl','$c','$ex',$cat_id,'$au','$im','$st',$views,$is_featured,$is_breaking,$is_top,$is_curated)";
    if ($conn->query($sql)) {
        if ($conn->affected_rows > 0) $ok++; else $skip++;
    } else {
        $err[] = $conn->error . ' — ' . $slug;
    }
}
// Mark top 4 economy posts as curated
$conn->query("UPDATE posts SET is_curated=1 WHERE category_id IN (SELECT id FROM categories WHERE slug='economy') ORDER BY views DESC LIMIT 2");
